using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Running;
using TextAnalysis;

BenchmarkRunner.Run<TextAnalyzerBenchmarks>();

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    private const string SampleText =
        "The quick brown fox jumps over the lazy dog. " +
        "A stitch in time saves nine. To be or not to be that is the question. " +
        "All that glitters is not gold. Actions speak louder than words. " +
        "Beauty is in the eye of the beholder. Better late than never. " +
        "Birds of a feather flock together. Cleanliness is next to godliness. " +
        "Do unto others as you would have them do unto you. " +
        "Every cloud has a silver lining. Fortune favors the bold. " +
        "Honesty is the best policy. Knowledge is power. " +
        "Look before you leap. No man is an island. " +
        "Practice makes perfect. Rome was not built in a day.";

    [GlobalSetup]
    public void Setup()
    {
        _analyzer = new TextAnalyzer(SampleText);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

